    height;
    boundOnMouseWheel;
    boundOnDragStart;
    boundOnDrag;
    boundOnPlotDblClick;
    boundOnZoomInClick;
    boundOnZoomWorldClick;
    boundOnZoomOutClick;
    boundOnLeftArrowClick;
    boundOnRightArrowClick;
    boundOnUpArrowClick;
    boundOnDownArrowClick;
